714 // where the reduction value (r) only has two states, in this example 0 or 3.
715 // The generated LLVM IR for this type of loop will be like this:
716 //   for.body:
717 //     %r = phi i32 [ %spec.select, %for.body ], [ 0, %entry ]
718 //     ...
719 //     %cmp = icmp sgt i32 %5, 3
720 //     %spec.select = select i1 %cmp, i32 3, i32 %r
721 //     ...
722 // In general we can support vectorization of loops where 'r' flips between
723 // any two non-constants, provided they are loop invariant. The only thing
724 // we actually care about at the end of the loop is whether or not any lane
725 // in the selected vector is different from the start value. The final
726 // across-vector reduction after the loop simply involves choosing the start
727 // value if nothing changed (0 in the example above) or the other selected
728 // value (3 in the example above).
729 RecurrenceDescriptor::InstDesc
730 RecurrenceDescriptor::isAnyOfPattern(Loop *Loop, PHINode *OrigPhi,
731                                      Instruction *I, InstDesc &Prev) {
732   // We must handle the select(cmp(),x,y) as a single instruction. Advance to
733   // the select.
734   if (match(I, m_OneUse(m_Cmp()))) {
735     if (auto *Select = dyn_cast<SelectInst>(*I->user_begin()))
736       return InstDesc(Select, Prev.getRecKind());
737   }
738 
739   if (!match(I, m_Select(m_Cmp(), m_Value(), m_Value())))
740     return InstDesc(false, I);
741 
742   SelectInst *SI = cast<SelectInst>(I);
743   Value *NonPhi = nullptr;
744 
745   if (OrigPhi == dyn_cast<PHINode>(SI->getTrueValue()))
746     NonPhi = SI->getFalseValue();
747   else if (OrigPhi == dyn_cast<PHINode>(SI->getFalseValue()))
748     NonPhi = SI->getTrueValue();
749   else
750     return InstDesc(false, I);
751 
752   // We are looking for selects of the form:
753   //   select(cmp(), phi, loop_invariant) or
754   //   select(cmp(), loop_invariant, phi)
755   if (!Loop->isLoopInvariant(NonPhi))
756     return InstDesc(false, I);
757 
758   return InstDesc(I, RecurKind::AnyOf);
759 }
