1305 bool VPlanTransforms::handleFindLastReductions(VPlan &Plan) {
1306   if (Plan.hasScalarVFOnly())
1307     return false;
1308 
1309   // We want to create the following nodes:
1310   // vector.body:
1311   //   ...new WidenPHI recipe introduced to keep the mask value for the latest
1312   //      iteration where any lane was active.
1313   //   mask.phi = phi [ ir<false>, vector.ph ], [ vp<new.mask>, vector.body ]
1314   //   ...data.phi (a VPReductionPHIRecipe for a FindLast reduction) already
1315   //      exists, but needs updating to use 'new.data' for the backedge value.
1316   //   data.phi = phi ir<default.val>, vp<new.data>
1317   //
1318   //   ...'data' and 'compare' created by existing nodes...
1319   //
1320   //   ...new recipes introduced to determine whether to update the reduction
1321   //      values or keep the current one.
1322   //   any.active = i1 any-of ir<compare>
1323   //   new.mask = select vp<any.active>, ir<compare>, vp<mask.phi>
1324   //   new.data = select vp<any.active>, ir<data>, ir<data.phi>
1325   //
1326   // middle.block:
1327   //   ...extract-last-active replaces compute-reduction-result.
1328   //   result = extract-last-active vp<new.data>, vp<new.mask>, ir<default.val>
1329 
1330   for (auto &Phi : Plan.getVectorLoopRegion()->getEntryBasicBlock()->phis()) {
1331     auto *PhiR = dyn_cast<VPReductionPHIRecipe>(&Phi);
1332     if (!PhiR || !RecurrenceDescriptor::isFindLastRecurrenceKind(
1333                      PhiR->getRecurrenceKind()))
1334       continue;
1335 
1336     // Find the condition for the select/blend.
1337     auto *SelectR = cast<VPSingleDefRecipe>(&PhiR->getBackedgeRecipe());
1338     VPValue *Cond = nullptr, *Op1 = nullptr, *Op2 = nullptr;
1339 
1340     // If we're matching a blend rather than a select, there should be one
1341     // incoming value which is the data, then all other incoming values should
1342     // be the phi.
1343     auto MatchBlend = [&](VPRecipeBase *R) {
1344       auto *Blend = dyn_cast<VPBlendRecipe>(R);
1345       if (!Blend)
1346         return false;
1347       assert(!Blend->isNormalized() && "must run before blend normalizaion");
1348       unsigned NumIncomingDataValues = 0;
1349       for (unsigned I = 0; I < Blend->getNumIncomingValues(); ++I) {
1350         VPValue *Incoming = Blend->getIncomingValue(I);
1351         if (Incoming != PhiR) {
1352           ++NumIncomingDataValues;
1353           Cond = Blend->getMask(I);
1354           Op1 = Incoming;
1355           Op2 = PhiR;
1356         }
1357       }
1358       return NumIncomingDataValues == 1;
1359     };
1360 
1361     if (!match(SelectR,
1362                m_Select(m_VPValue(Cond), m_VPValue(Op1), m_VPValue(Op2))) &&
1363         !MatchBlend(SelectR))
1364       return false;
1365 
1366     // Add mask phi.
1367     VPBuilder Builder = VPBuilder::getToInsertAfter(PhiR);
1368     auto *MaskPHI = new VPWidenPHIRecipe(nullptr, /*Start=*/Plan.getFalse());
1369     Builder.insert(MaskPHI);
1370 
1371     // Add select for mask.
1372     Builder.setInsertPoint(SelectR);
1373 
1374     if (Op1 == PhiR) {
1375       // Normalize to selecting the data operand when the condition is true by
1376       // swapping operands and negating the condition.
1377       std::swap(Op1, Op2);
1378       Cond = Builder.createNot(Cond);
1379     }
1380     assert(Op2 == PhiR && "data value must be selected if Cond is true");
1381 
1382     VPValue *AnyOf = Builder.createNaryOp(VPInstruction::AnyOf, {Cond});
1383     VPValue *MaskSelect = Builder.createSelect(AnyOf, Cond, MaskPHI);
1384     MaskPHI->addOperand(MaskSelect);
1385 
1386     // Replace select for data.
1387     VPValue *DataSelect =
1388         Builder.createSelect(AnyOf, Op1, Op2, SelectR->getDebugLoc());
1389     SelectR->replaceAllUsesWith(DataSelect);
1390     SelectR->eraseFromParent();
1391 
1392     // Find final reduction computation and replace it with an
1393     // extract.last.active intrinsic.
1394     auto *RdxResult =
1395         vputils::findUserOf<VPInstruction::ComputeReductionResult>(DataSelect);
1396     // TODO: Handle tail-folding.
1397     if (!RdxResult)
1398       return false;
1399     Builder.setInsertPoint(RdxResult);
1400     auto *ExtractLastActive =
1401         Builder.createNaryOp(VPInstruction::ExtractLastActive,
1402                              {DataSelect, MaskSelect, PhiR->getStartValue()},
1403                              RdxResult->getDebugLoc());
1404     RdxResult->replaceAllUsesWith(ExtractLastActive);
1405     RdxResult->eraseFromParent();
1406   }
1407 
1408   return true;
1409 }
