264 // This matches a phi that selects between the original value (HeaderPhi) and an
265 // arbitrary non-reduction value.
266 static bool isFindLastLikePhi(PHINode *Phi, PHINode *HeaderPhi,
267                               SmallPtrSetImpl<Instruction *> &ReductionInstrs) {
268   unsigned NumNonReduxInputs = 0;
269   for (const Value *Op : Phi->operands()) {
270     if (!ReductionInstrs.contains(dyn_cast<Instruction>(Op))) {
271       if (++NumNonReduxInputs > 1)
272         return false;
273     } else if (Op != HeaderPhi) {
274       // TODO: Remove this restriction once chained phis are supported.
275       return false;
276     }
277   }
278   return NumNonReduxInputs == 1;
279 }
