 813 RecurrenceDescriptor::InstDesc
 814 RecurrenceDescriptor::isMinMaxPattern(Instruction *I, RecurKind Kind,
 815                                       const InstDesc &Prev) {
 816   assert((isa<CmpInst>(I) || isa<SelectInst>(I) || isa<CallInst>(I)) &&
 817          "Expected a cmp or select or call instruction");
 818   if (!isMinMaxRecurrenceKind(Kind))
 819     return InstDesc(false, I);
 820 
 821   // We must handle the select(cmp()) as a single instruction. Advance to the
 822   // select.
 823   if (match(I, m_OneUse(m_Cmp()))) {
 824     if (auto *Select = dyn_cast<SelectInst>(*I->user_begin()))
 825       return InstDesc(Select, Prev.getRecKind());
 826   }
 827 
 828   // Only match select with single use cmp condition, or a min/max intrinsic.
 829   if (!isa<IntrinsicInst>(I) &&
 830       !match(I, m_Select(m_OneUse(m_Cmp()), m_Value(), m_Value())))
 831     return InstDesc(false, I);
 832 
 833   // Look for a min/max pattern.
 834   if (match(I, m_UMin(m_Value(), m_Value())))
 835     return InstDesc(Kind == RecurKind::UMin, I);
 836   if (match(I, m_UMax(m_Value(), m_Value())))
 837     return InstDesc(Kind == RecurKind::UMax, I);
 838   if (match(I, m_SMax(m_Value(), m_Value())))
 839     return InstDesc(Kind == RecurKind::SMax, I);
 840   if (match(I, m_SMin(m_Value(), m_Value())))
 841     return InstDesc(Kind == RecurKind::SMin, I);
 842   if (match(I, m_OrdOrUnordFMin(m_Value(), m_Value())))
 843     return InstDesc(Kind == RecurKind::FMin, I);
 844   if (match(I, m_OrdOrUnordFMax(m_Value(), m_Value())))
 845     return InstDesc(Kind == RecurKind::FMax, I);
 846   if (match(I, m_FMinNum(m_Value(), m_Value())))
 847     return InstDesc(Kind == RecurKind::FMin, I);
 848   if (match(I, m_FMaxNum(m_Value(), m_Value())))
 849     return InstDesc(Kind == RecurKind::FMax, I);
 850   if (match(I, m_FMinimumNum(m_Value(), m_Value())))
 851     return InstDesc(Kind == RecurKind::FMinimumNum, I);
 852   if (match(I, m_FMaximumNum(m_Value(), m_Value())))
 853     return InstDesc(Kind == RecurKind::FMaximumNum, I);
 854   if (match(I, m_FMinimum(m_Value(), m_Value())))
 855     return InstDesc(Kind == RecurKind::FMinimum, I);
 856   if (match(I, m_FMaximum(m_Value(), m_Value())))
 857     return InstDesc(Kind == RecurKind::FMaximum, I);
 858 
 859   return InstDesc(false, I);
 860 }
