 862 /// Returns true if the select instruction has users in the compare-and-add
 863 /// reduction pattern below. The select instruction argument is the last one
 864 /// in the sequence.
 865 ///
 866 /// %sum.1 = phi ...
 867 /// ...
 868 /// %cmp = fcmp pred %0, %CFP
 869 /// %add = fadd %0, %sum.1
 870 /// %sum.2 = select %cmp, %add, %sum.1
 871 RecurrenceDescriptor::InstDesc
 872 RecurrenceDescriptor::isConditionalRdxPattern(Instruction *I) {
 873   Value *TrueVal, *FalseVal;
 874   // Only handle single use cases for now.
 875   if (!match(I,
 876              m_Select(m_OneUse(m_Cmp()), m_Value(TrueVal), m_Value(FalseVal))))
 877     return InstDesc(false, I);
 878 
 879   // Handle only when either of operands of select instruction is a PHI
 880   // node for now.
 881   if ((isa<PHINode>(TrueVal) && isa<PHINode>(FalseVal)) ||
 882       (!isa<PHINode>(TrueVal) && !isa<PHINode>(FalseVal)))
 883     return InstDesc(false, I);
 884 
 885   Instruction *I1 = isa<PHINode>(TrueVal) ? dyn_cast<Instruction>(FalseVal)
 886                                           : dyn_cast<Instruction>(TrueVal);
 887   if (!I1 || !I1->isBinaryOp())
 888     return InstDesc(false, I);
 889 
 890   Value *Op1, *Op2;
 891   if (!(((m_FAdd(m_Value(Op1), m_Value(Op2)).match(I1) ||
 892           m_FSub(m_Value(Op1), m_Value(Op2)).match(I1)) &&
 893          I1->isFast()) ||
 894         (m_FMul(m_Value(Op1), m_Value(Op2)).match(I1) && (I1->isFast())) ||
 895         ((m_Add(m_Value(Op1), m_Value(Op2)).match(I1) ||
 896           m_Sub(m_Value(Op1), m_Value(Op2)).match(I1))) ||
 897         (m_Mul(m_Value(Op1), m_Value(Op2)).match(I1))))
 898     return InstDesc(false, I);
 899 
 900   Instruction *IPhi = isa<PHINode>(Op1) ? dyn_cast<Instruction>(Op1)
 901                                         : dyn_cast<Instruction>(Op2);
 902   if (!IPhi || IPhi != FalseVal)
 903     return InstDesc(false, I);
 904 
 905   return InstDesc(true, I);
 906 }
