 908 RecurrenceDescriptor::InstDesc RecurrenceDescriptor::isRecurrenceInstr(
 909     Loop *L, PHINode *OrigPhi, Instruction *I, RecurKind Kind, InstDesc &Prev,
 910     FastMathFlags FuncFMF, ScalarEvolution *SE) {
 911   assert(Prev.getRecKind() == RecurKind::None || Prev.getRecKind() == Kind);
 912   switch (I->getOpcode()) {
 913   default:
 914     return InstDesc(false, I);
 915   case Instruction::PHI:
 916     return InstDesc(I, Prev.getRecKind(), Prev.getExactFPMathInst());
 917   case Instruction::Sub:
 918     return InstDesc(
 919         Kind == RecurKind::Sub || Kind == RecurKind::AddChainWithSubs, I);
 920   case Instruction::Add:
 921     return InstDesc(
 922         Kind == RecurKind::Add || Kind == RecurKind::AddChainWithSubs, I);
 923   case Instruction::Mul:
 924     return InstDesc(Kind == RecurKind::Mul, I);
 925   case Instruction::And:
 926     return InstDesc(Kind == RecurKind::And, I);
 927   case Instruction::Or:
 928     return InstDesc(Kind == RecurKind::Or, I);
 929   case Instruction::Xor:
 930     return InstDesc(Kind == RecurKind::Xor, I);
 931   case Instruction::FDiv:
 932   case Instruction::FMul:
 933     return InstDesc(Kind == RecurKind::FMul, I,
 934                     I->hasAllowReassoc() ? nullptr : I);
 935   case Instruction::FSub:
 936   case Instruction::FAdd:
 937     return InstDesc(Kind == RecurKind::FAdd, I,
 938                     I->hasAllowReassoc() ? nullptr : I);
 939   case Instruction::Select:
 940     if (Kind == RecurKind::FAdd || Kind == RecurKind::FMul ||
 941         Kind == RecurKind::Add || Kind == RecurKind::Mul ||
 942         Kind == RecurKind::Sub || Kind == RecurKind::AddChainWithSubs)
 943       return isConditionalRdxPattern(I);
 944     if (isFindRecurrenceKind(Kind) && SE)
 945       return isFindPattern(L, OrigPhi, I, *SE);
 946     [[fallthrough]];
 947   case Instruction::FCmp:
 948   case Instruction::ICmp:
 949   case Instruction::Call:
 950     if (isAnyOfRecurrenceKind(Kind))
 951       return isAnyOfPattern(L, OrigPhi, I, Prev);
 952     auto HasRequiredFMF = [&]() {
 953      if (FuncFMF.noNaNs() && FuncFMF.noSignedZeros())
 954        return true;
 955      if (isa<FPMathOperator>(I) && I->hasNoNaNs() && I->hasNoSignedZeros())
 956        return true;
 957      // minimum/minnum and maximum/maxnum intrinsics do not require nsz and nnan
 958      // flags since NaN and signed zeroes are propagated in the intrinsic
 959      // implementation.
 960      return match(I, m_Intrinsic<Intrinsic::minimum>(m_Value(), m_Value())) ||
 961             match(I, m_Intrinsic<Intrinsic::maximum>(m_Value(), m_Value())) ||
 962             match(I,
 963                   m_Intrinsic<Intrinsic::minimumnum>(m_Value(), m_Value())) ||
 964             match(I, m_Intrinsic<Intrinsic::maximumnum>(m_Value(), m_Value()));
 965     };
 966     if (isIntMinMaxRecurrenceKind(Kind))
 967       return isMinMaxPattern(I, Kind, Prev);
 968     if (isFPMinMaxRecurrenceKind(Kind)) {
 969       InstDesc Res = isMinMaxPattern(I, Kind, Prev);
 970       if (!Res.isRecurrence())
 971         return InstDesc(false, I);
 972       if (HasRequiredFMF())
 973         return Res;
 974       // We may be able to vectorize FMax/FMin reductions using maxnum/minnum
 975       // intrinsics with extra checks ensuring the vector loop handles only
 976       // non-NaN inputs.
 977       if (match(I, m_Intrinsic<Intrinsic::maxnum>(m_Value(), m_Value()))) {
 978         assert(Kind == RecurKind::FMax &&
 979                "unexpected recurrence kind for maxnum");
 980         return InstDesc(I, RecurKind::FMaxNum);
 981       }
 982       if (match(I, m_Intrinsic<Intrinsic::minnum>(m_Value(), m_Value()))) {
 983         assert(Kind == RecurKind::FMin &&
 984                "unexpected recurrence kind for minnum");
 985         return InstDesc(I, RecurKind::FMinNum);
 986       }
 987       return InstDesc(false, I);
 988     }
 989     if (isFMulAddIntrinsic(I))
 990       return InstDesc(Kind == RecurKind::FMulAdd, I,
 991                       I->hasAllowReassoc() ? nullptr : I);
 992     return InstDesc(false, I);
 993   }
